from flask import Flask, request, jsonify
from web3 import Web3
from eth_account.messages import encode_defunct
import os
import secrets
import time

app = Flask(__name__)

w3 = Web3()

NONCE_TTL_SECONDS = int(os.getenv("NONCE_TTL_SECONDS", "300"))
nonces = {}
authenticated_sessions = {}

def now_ts():
    return int(time.time())

def prune_expired():
    current = now_ts()
    expired_nonces = [addr for addr, data in nonces.items() if data["expires_at"] < current]
    for addr in expired_nonces:
        nonces.pop(addr, None)

    expired_sessions = [token for token, data in authenticated_sessions.items() if data["expires_at"] < current]
    for token in expired_sessions:
        authenticated_sessions.pop(token, None)

def normalize_address(address: str) -> str:
    if not isinstance(address, str):
        raise ValueError("Address must be a string")
    if not w3.is_address(address):
        raise ValueError("Invalid Ethereum address")
    return w3.to_checksum_address(address)

@app.route("/health", methods=["GET"])
def health():
    return jsonify({"status": "ok"})

@app.route("/auth/nonce", methods=["POST"])
def get_nonce():
    prune_expired()
    data = request.get_json(silent=True) or {}
    address = data.get("address")

    if not address:
        return jsonify({"error": "Missing address"}), 400

    try:
        address = normalize_address(address)
    except ValueError as e:
        return jsonify({"error": str(e)}), 400

    nonce = secrets.token_urlsafe(24)
    message = f"Sign this message to authenticate.\n\nAddress: {address}\nNonce: {nonce}\nIssued At: {now_ts()}"
    nonces[address] = {
        "nonce": nonce,
        "message": message,
        "expires_at": now_ts() + NONCE_TTL_SECONDS,
    }

    return jsonify({
        "address": address,
        "nonce": nonce,
        "message": message,
        "expires_at": nonces[address]["expires_at"],
    })

@app.route("/auth/verify", methods=["POST"])
def verify_signature():
    prune_expired()
    data = request.get_json(silent=True) or {}

    address = data.get("address")
    signature = data.get("signature")
    message = data.get("message")

    if not address or not signature or not message:
        return jsonify({"error": "Missing address, signature, or message"}), 400

    try:
        address = normalize_address(address)
    except ValueError as e:
        return jsonify({"error": str(e)}), 400

    nonce_record = nonces.get(address)
    if not nonce_record:
        return jsonify({"error": "No active nonce for address"}), 400

    if nonce_record["message"] != message:
        return jsonify({"error": "Message does not match issued nonce"}), 400

    if nonce_record["expires_at"] < now_ts():
        nonces.pop(address, None)
        return jsonify({"error": "Nonce expired"}), 400

    try:
        encoded_message = encode_defunct(text=message)
        recovered_address = w3.eth.account.recover_message(encoded_message, signature=signature)
        recovered_address = w3.to_checksum_address(recovered_address)
    except Exception as e:
        return jsonify({"error": f"Signature verification failed: {str(e)}"}), 400

    if recovered_address != address:
        return jsonify({
            "authenticated": False,
            "error": "Recovered address does not match provided address",
            "recovered_address": recovered_address,
        }), 401

    session_token = secrets.token_urlsafe(32)
    authenticated_sessions[session_token] = {
        "address": address,
        "authenticated_at": now_ts(),
        "expires_at": now_ts() + 86400,
    }

    nonces.pop(address, None)

    return jsonify({
        "authenticated": True,
        "address": address,
        "recovered_address": recovered_address,
        "session_token": session_token,
        "expires_at": authenticated_sessions[session_token]["expires_at"],
    })

@app.route("/auth/session", methods=["GET"])
def validate_session():
    prune_expired()
    auth_header = request.headers.get("Authorization", "")
    if not auth_header.startswith("Bearer "):
        return jsonify({"error": "Missing or invalid Authorization header"}), 401

    token = auth_header.split(" ", 1)[1].strip()
    session = authenticated_sessions.get(token)
    if not session:
        return jsonify({"authenticated": False}), 401

    return jsonify({
        "authenticated": True,
        "address": session["address"],
        "authenticated_at": session["authenticated_at"],
        "expires_at": session["expires_at"],
    })

@app.route("/auth/logout", methods=["POST"])
def logout():
    prune_expired()
    auth_header = request.headers.get("Authorization", "")
    if not auth_header.startswith("Bearer "):
        return jsonify({"error": "Missing or invalid Authorization header"}), 401

    token = auth_header.split(" ", 1)[1].strip()
    authenticated_sessions.pop(token, None)
    return jsonify({"success": True})

